import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { violationsAPI } from '../../services/api';
import Card from '../../components/common/Card';
import { FileText, AlertTriangle } from 'lucide-react';

const StudentViolations = () => {
  const { user } = useAuth();
  const [violations, setViolations] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchViolations();
  }, []);

  const fetchViolations = async () => {
    try {
      // Get student profile first to get student id
      const response = await violationsAPI.getByStudent(user.id);
      if (response.data.success) {
        setViolations(response.data.violations);
      }
    } catch (error) {
      console.error('Error fetching violations:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  const pendingCount = violations.filter(v => v.status === 'Pending').length;
  const resolvedCount = violations.filter(v => v.status === 'Resolved').length;

  return (
    <div className="space-y-6 animate-fade-in">
      <h1 className="text-2xl font-bold text-secondary-800">My Violations</h1>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card>
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-secondary-100 rounded-lg flex items-center justify-center">
              <FileText className="w-6 h-6 text-secondary-600" />
            </div>
            <div>
              <p className="text-sm text-secondary-500">Total Violations</p>
              <p className="text-2xl font-bold text-secondary-800">{violations.length}</p>
            </div>
          </div>
        </Card>
        <Card>
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-yellow-100 rounded-lg flex items-center justify-center">
              <AlertTriangle className="w-6 h-6 text-yellow-600" />
            </div>
            <div>
              <p className="text-sm text-secondary-500">Pending</p>
              <p className="text-2xl font-bold text-yellow-600">{pendingCount}</p>
            </div>
          </div>
        </Card>
        <Card>
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center">
              <FileText className="w-6 h-6 text-green-600" />
            </div>
            <div>
              <p className="text-sm text-secondary-500">Resolved</p>
              <p className="text-2xl font-bold text-green-600">{resolvedCount}</p>
            </div>
          </div>
        </Card>
      </div>

      {/* Violations List */}
      <Card title="Violation Records">
        {violations.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-secondary-200">
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Date</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Violation Type</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Status</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Remarks</th>
                </tr>
              </thead>
              <tbody>
                {violations.map((violation) => (
                  <tr key={violation.id} className="border-b border-secondary-100 hover:bg-secondary-50">
                    <td className="py-3 px-4">{violation.date}</td>
                    <td className="py-3 px-4 font-medium">{violation.violation_type}</td>
                    <td className="py-3 px-4">
                      <span className={`px-3 py-1 rounded-full text-sm ${
                        violation.status === 'Pending'
                          ? 'bg-yellow-100 text-yellow-700'
                          : 'bg-green-100 text-green-700'
                      }`}>
                        {violation.status}
                      </span>
                    </td>
                    <td className="py-3 px-4 text-secondary-600">{violation.remarks || '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="text-center py-8 text-secondary-500">
            <FileText className="w-12 h-12 mx-auto mb-3 text-secondary-300" />
            <p>No violations recorded</p>
          </div>
        )}
      </Card>
    </div>
  );
};

export default StudentViolations;
